public class MergeTwo {
    public static void main(String[] args) {
        int[] a = {2, 4, 6};
        int[] b = {1, 3, 5, 7};
        int[] c = new int[a.length + b.length];
        for (int i = 0; i < a.length; i++)
            c[i] = a[i];
        for (int i = 0; i < b.length; i++)
